<?php
namespace App\Domain\Repayments\Actions;
use App\Domain\Credit\Services\RepaymentScheduleGenerator;use App\Enums\InstallmentStatus;use App\Enums\LoanStatus;use App\Enums\RepaymentFrequency;use App\Enums\RestructureStatus;use App\Models\Loan;use App\Models\LoanRestructure;use Carbon\CarbonImmutable;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Facades\DB;use Illuminate\Support\Str;use Illuminate\Validation\ValidationException;
class RestructureLoan{public function __construct(private RepaymentScheduleGenerator $schedules){}public function request(Loan $loan,array $data):LoanRestructure{$loan->loadMissing(['product','installments']);$newPrincipal=$loan->outstanding_minor+(int)($data['capitalized_arrears_minor']??0);$product=$loan->product->replicate();$product->minimum_principal_minor=1;$product->maximum_principal_minor=max($newPrincipal,$product->maximum_principal_minor);$product->minimum_tenure=1;$product->maximum_tenure=max($data['new_tenure'],$product->maximum_tenure);$product->annual_interest_rate_basis_points=$data['new_interest_rate_basis_points']??$product->annual_interest_rate_basis_points;$product->repayment_frequency=isset($data['new_repayment_frequency'])?RepaymentFrequency::from($data['new_repayment_frequency']):$product->repayment_frequency;$schedule=$this->schedules->generate($product,$newPrincipal,$data['new_tenure'],CarbonImmutable::parse($data['new_start_date']));return LoanRestructure::query()->create(['loan_id'=>$loan->id,'reference'=>'RST-'.strtoupper(Str::ulid()),'reason'=>$data['reason'],'status'=>RestructureStatus::Pending,'capitalized_arrears_minor'=>$data['capitalized_arrears_minor']??0,'new_interest_rate_basis_points'=>$data['new_interest_rate_basis_points']??null,'new_repayment_frequency'=>$data['new_repayment_frequency']??null,'new_tenure'=>$data['new_tenure'],'new_start_date'=>$data['new_start_date'],'old_schedule_snapshot'=>$loan->installments->toArray(),'new_schedule_snapshot'=>$schedule,'requested_by'=>Auth::id()]);}public function decide(LoanRestructure $restructure,string $decision,string $reason):LoanRestructure{if($restructure->status!==RestructureStatus::Pending)throw ValidationException::withMessages(['status'=>['Only pending restructures can be decided.']]);if($restructure->requested_by===Auth::id())throw ValidationException::withMessages(['actor'=>['The requester cannot approve the restructure.']]);$restructure->update(['status'=>$decision==='approve'?RestructureStatus::Approved:RestructureStatus::Rejected,'decided_by'=>Auth::id(),'decided_at'=>now(),'decision_reason'=>$reason]);return $restructure->refresh();}public function apply(LoanRestructure $restructure):LoanRestructure{return DB::transaction(function()use($restructure){$restructure=LoanRestructure::query()->lockForUpdate()->findOrFail($restructure->id);if($restructure->status!==RestructureStatus::Approved)throw ValidationException::withMessages(['status'=>['Only approved restructures can be applied.']]);$loan=Loan::query()->lockForUpdate()->findOrFail($restructure->loan_id);$loan->installments()->whereNotIn('status',[InstallmentStatus::Paid->value,InstallmentStatus::Waived->value])->update(['status'=>InstallmentStatus::Rescheduled]);$offset=(int)$loan->installments()->max('installment_number');foreach($restructure->new_schedule_snapshot['installments'] as $row)$loan->installments()->create(['installment_number'=>$offset+$row['installment_number'],'due_date'=>$row['due_date'],'principal_due_minor'=>$row['principal_minor'],'interest_due_minor'=>$row['interest_minor'],'status'=>InstallmentStatus::Upcoming]);$loan->update(['interest_minor'=>$loan->interest_minor+$restructure->new_schedule_snapshot['interest_minor'],'repayable_minor'=>$loan->repayable_minor+$restructure->capitalized_arrears_minor+$restructure->new_schedule_snapshot['interest_minor'],'outstanding_minor'=>$restructure->new_schedule_snapshot['repayable_minor'],'maturity_date'=>collect($restructure->new_schedule_snapshot['installments'])->last()['due_date'],'status'=>LoanStatus::Restructured]);$restructure->update(['status'=>RestructureStatus::Applied,'applied_at'=>now()]);return $restructure->refresh();});}}
